package day1;

/**
 * 
 */
public class Program9_Increment {

	/**
	 * @param args
	 */
	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int num3=10;
		num3= num3 +1;
		System.out.println(num3);
		num3++;
		System.out.println(num3);
		++num3;
		System.out.println(num3);
		System.out.println(num3++);
		System.out.println(num3);
		System.out.println(++num3);
		System.out.println(num3);
	}

}
